"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[14280],{21308:e=>{e.exports=JSON.parse('{"tag":{"label":"spider","permalink":"/dst-api-webdocs/docs/tags/spider","allTagsPath":"/dst-api-webdocs/docs/tags","count":15,"items":[{"id":"game-scripts/components/bedazzlement","title":"Bedazzlement","description":"Manages the bedazzled state for a spider den, applying visual and gameplay effects such as pacifying nearby spiders and altering creep radius.","permalink":"/dst-api-webdocs/docs/game-scripts/components/bedazzlement"},{"id":"game-scripts/map/rooms/forest/spider","title":"Spider","description":"Defines three procedural room templates (SpiderCity, SpiderVillage, SpiderVillageSwamp) for generating spider-infested areas in the Forest, Rocky, and Marsh biomes.","permalink":"/dst-api-webdocs/docs/game-scripts/map/rooms/forest/spider"},{"id":"game-scripts/map/static_layouts/spider_blocker","title":"Spider Blocker","description":"A static layout definition for a 40x40 world region containing evergreen trees and fully mature spider dens, used to block or partition map areas in procedural generation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/spider_blocker"},{"id":"game-scripts/map/static_layouts/spider_blocker_easy","title":"Spider Blocker Easy","description":"Defines a static map layout used as a beginner-friendly spider den blocker with three spider dens and vegetation.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/spider_blocker_easy"},{"id":"game-scripts/map/static_layouts/spider_blocker_easy_b","title":"Spider Blocker Easy B","description":"A static layout file defining map content for a spider-blocking area, specifying background tiles and object placements including spider dens at growth stage 1 or 2.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/spider_blocker_easy_b"},{"id":"game-scripts/prefabs/spider_healer_item","title":"Spider Healer Item","description":"A consumable item that heals the Spider Whisperer and nearby spiders when used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_healer_item"},{"id":"game-scripts/prefabs/spider_mutators","title":"Spider Mutators","description":"Generates prefabs for spider mutator items, each representing a specific spider subtype and enabling mutation of spider entities when consumed.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_mutators"},{"id":"game-scripts/prefabs/spider_repellent","title":"Spider Repellent","description":"A consumable item that repels spiders while reducing stack usage over time.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_repellent"},{"id":"game-scripts/prefabs/spider_whistle","title":"Spider Whistle","description":"A consumable item that summons spiders from dens and wakes up sleeping spiders within range, while granting temporary buffs to nearby spider followers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_whistle"},{"id":"game-scripts/brains/spiderbrain","title":"Spiderbrain","description":"Manages the AI behavior tree for spiders, handling combat, following, hiding, foraging, and navigation based on spider type and state.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/spiderbrain"},{"id":"game-scripts/prefabs/spiderden_bedazzler","title":"Spiderden Bedazzler","description":"A single-use consumable item that applies a bedazzling buff to a target upon use, designed for spider-related gameplay interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spiderden_bedazzler"},{"id":"game-scripts/prefabs/spiderhole","title":"Spiderhole","description":"A spawner entity that periodically generates spider minions and releases them when mined; it transforms into a mineable rock when fully depleted.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spiderhole"},{"id":"game-scripts/components/spidermutator","title":"Spidermutator","description":"Handles the conversion of one spider type into another, typically used when a spider consumes a mutator item.","permalink":"/dst-api-webdocs/docs/game-scripts/components/spidermutator"},{"id":"game-scripts/prefabs/webber","title":"Webber","description":"Provides the implementation for the Webber character, a spider-taming player character with unique beard mechanics, spider affinity, and creep-based movement bonuses.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/webber"},{"id":"game-scripts/prefabs/webber_spider_minions","title":"Webber Spider Minions","description":"Defines the asset and initialization logic for Webber\'s spider minion prefabs in DST, including physics, animation, sound, and network properties.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/webber_spider_minions"}],"unlisted":false}}')}}]);